import{_ as e,o as t,c as r,ag as o}from"./chunks/framework.C9sp7nFj.js";const m=JSON.parse('{"title":"了解 Memoh","description":"","frontmatter":{},"headers":[],"relativePath":"zh/about.md","filePath":"zh/about.md","lastUpdated":1777012567000}'),s={name:"zh/about.md"};function i(l,a,h,n,d,c){return t(),r("div",null,[...a[0]||(a[0]=[o('<h1 id="了解-memoh" tabindex="-1">了解 Memoh <a class="header-anchor" href="#了解-memoh" aria-label="Permalink to &quot;了解 Memoh&quot;">​</a></h1><h2 id="memoh-是什么" tabindex="-1">Memoh 是什么 <a class="header-anchor" href="#memoh-是什么" aria-label="Permalink to &quot;Memoh 是什么&quot;">​</a></h2><p>Memoh 是面向多成员、可结构化长期记忆、容器化运行的 AI 智能体平台。你可以创建多个机器人，为每个机器人提供独立工作区和长期记忆，通过 Telegram、Discord、飞书、QQ、Matrix、Misskey、钉钉、企微、微信、微信公众号、邮件或自带网页界面使用。</p><p>每个机器人有各自的运行环境、工具、记忆与渠道。用起来更像「每人一台小电脑上的智能体」，而不是所有人共用一条聊天人格。</p><h2 id="和其它方案不一样在哪" tabindex="-1">和其它方案不一样在哪 <a class="header-anchor" href="#和其它方案不一样在哪" aria-label="Permalink to &quot;和其它方案不一样在哪&quot;">​</a></h2><h3 id="多机器人、多用户" tabindex="-1">多机器人、多用户 <a class="header-anchor" href="#多机器人、多用户" aria-label="Permalink to &quot;多机器人、多用户&quot;">​</a></h3><ul><li>一个账号里可建多个机器人，分角色或分场景用。</li><li>私聊、群聊、委派的流程里，人和机器人都可参与。</li><li>共享对话里能区分不同用户；跨渠道绑定身份后，同一个人可被稳定识别。</li></ul><h3 id="容器化工作区" tabindex="-1">容器化工作区 <a class="header-anchor" href="#容器化工作区" aria-label="Permalink to &quot;容器化工作区&quot;">​</a></h3><p>每个机器人在自己的容器里跑，有独立文件系统和网络边界。机器人在工作区内读写文件、跑命令、用工具，不会踩到别的机器人。</p><h3 id="长期记忆与会话负担" tabindex="-1">长期记忆与会话负担 <a class="header-anchor" href="#长期记忆与会话负担" aria-label="Permalink to &quot;长期记忆与会话负担&quot;">​</a></h3><p>这是两件不同的事：</p><ul><li><strong>长期记忆</strong>通过各记忆提供方存事实、跨会话检索。</li><li><strong>会话上下文压缩</strong>是在「当前这一串对话」太长时，用摘要把活跃窗口缩小。</li></ul><p>注意：压缩会话上下文，改的是当前对话窗口；<strong>记忆压缩</strong>（在记忆 tab）改的是存下来的记忆条目本身。</p><h3 id="会话与-discuss-模式" tabindex="-1">会话与 Discuss 模式 <a class="header-anchor" href="#会话与-discuss-模式" aria-label="Permalink to &quot;会话与 Discuss 模式&quot;">​</a></h3><p>每个机器人有多路 <strong>会话</strong>，自带上下文。Memoh 里常见五类：</p><ul><li><strong>Chat</strong>：普通面向人的对话。</li><li><strong>Discuss</strong>：偏观察；模型先在内心里组织语言，只有在你用发送类动作时才算真正对频道说话。</li><li><strong>Heartbeat</strong>：按间隔自动跑的任务会话。</li><li><strong>Schedule</strong>：由 cron 触发的任务会话。</li><li><strong>Subagent</strong>：委派子智能体时产生的会话。</li></ul><p>在渠道里可以用 <code>/new</code> 等切会话，网页端也有会话侧栏，可看上下文占用、缓存命中、用到的技能等。</p><h3 id="渠道覆盖面" tabindex="-1">渠道覆盖面 <a class="header-anchor" href="#渠道覆盖面" aria-label="Permalink to &quot;渠道覆盖面&quot;">​</a></h3><p>用统一的渠道适配，让一个机器人能同时在多个地方被叫到。当前可对接例如 Telegram、Discord、飞书、QQ、Matrix、Misskey、钉钉、企微、微信、公众号、邮件、Web。</p><p><strong>个人微信扫码</strong>与<strong>公众号 Webhook</strong> 是两套不同适配，别混用。</p><h3 id="工具、技能、mcp、超市" tabindex="-1">工具、技能、MCP、超市 <a class="header-anchor" href="#工具、技能、mcp、超市" aria-label="Permalink to &quot;工具、技能、MCP、超市&quot;">​</a></h3><p>内置能力包括：网页搜索与拉取、浏览器自动化、工作区内改文件/跑命令、记忆检索与管理、发消息/邮件、TTS、子智能体、可复用 <strong>技能</strong> 模块、外部 <strong>MCP</strong> 服务、以及从 <strong>超市</strong> 装技能和 MCP 模板。</p><h3 id="供应商与模型" tabindex="-1">供应商与模型 <a class="header-anchor" href="#供应商与模型" aria-label="Permalink to &quot;供应商与模型&quot;">​</a></h3><p>支持多种对接方式，例如：OpenAI 系 Chat/Responses、Anthropic Messages、Google、Codex、GitHub Copilot、Edge 朗读等。模型按 <strong>chat / embedding / speech</strong> 分角色。文生图走兼容的 chat/图像能力，不单独做一层「图像供应商系统」。</p><h3 id="运维与界面" tabindex="-1">运维与界面 <a class="header-anchor" href="#运维与界面" aria-label="Permalink to &quot;运维与界面&quot;">​</a></h3><p>网页端尽量把日常事做完：机器人各 tab、供应商与模型（含部分 OAuth）、会话里即时压缩与状态、技能显隐、渠道里用斜杠命令。不必天天手改配置文件。</p><h2 id="从哪开始" tabindex="-1">从哪开始 <a class="header-anchor" href="#从哪开始" aria-label="Permalink to &quot;从哪开始&quot;">​</a></h2><ul><li><a href="/zh/installation/docker.html">Docker 安装</a> — 先把服务跑起来</li><li><a href="/zh/getting-started/provider-and-model.html">供应商与模型</a> — 配好模型访问</li><li><a href="/zh/getting-started/bot.html">机器人</a> — 创建并配置</li><li><a href="/zh/getting-started/sessions.html">会话</a> — 弄清 chat 与 discuss</li><li><a href="/zh/getting-started/channels.html">渠道</a> — 选机器人出现的位置</li><li><a href="/zh/getting-started/skills.html">技能</a>、<a href="/zh/getting-started/supermarket.html">超市</a> — 扩展能力</li><li><a href="/zh/getting-started/slash-commands.html">斜杠命令</a> — 在聊天里直接操控</li></ul>',28)])])}const u=e(s,[["render",i]]);export{m as __pageData,u as default};
